#include<bits/stdc++.h>
using namespace std;
long long b[500010];
const long long mod=998244353;
struct segment_tree
{
	struct node
	{
		long long l,r,sum[2],max1,min1;
		long long lson,rson;
		long long tag;
		node():tag(0){}
	}a[1500010];
	long long cnt;
	segment_tree():cnt(0){}
	void pushup(long long x)
	{
        a[x].sum[0]=(a[a[x].lson].sum[0]+a[a[x].rson].sum[0])%mod;
        a[x].sum[1]=(a[a[x].lson].sum[1]+a[a[x].rson].sum[1])%mod;
        a[x].max1=max(a[a[x].lson].max1,a[a[x].rson].max1);
        a[x].min1=min(a[a[x].lson].min1,a[a[x].rson].min1);
	}
	long long init(long long l,long long r)
	{
		long long x=++cnt,mid=(l+r)>>1;
		a[x].l=l;
		a[x].r=r;
		if(l==r)
		{
            a[x].max1=a[x].min1=b[l]%mod;
            a[x].sum[0]=b[l]%mod*b[l]%mod;
            a[x].sum[1]=b[l]%mod*b[l]%mod*b[l]%mod;
			return x;
		}
		a[x].lson=init(l,mid);
		a[x].rson=init(mid+1,r);
		pushup(x);
		return x;
	}
	void update(long long x,long long p,long long z)
	{
		if(a[x].l>p||a[x].r<p)
		{
			return;
		}
		if(a[x].l==a[x].r)
		{
            a[x].max1=a[x].min1=z%mod;
            a[x].sum[0]=z%mod*z%mod;
            a[x].sum[1]=z%mod*z%mod*z%mod;
			return;
		}
		update(a[x].lson,p,z);
		update(a[x].rson,p,z);
		pushup(x);
	}
	long long getsum(long long x,long long l,long long r,long long id)
	{
		if(a[x].l>r||a[x].r<l)
		{
			return 0;
		}
		if(a[x].l>=l&&a[x].r<=r)
		{
			return a[x].sum[id];
		}
		return (getsum(a[x].lson,l,r,id)+getsum(a[x].rson,l,r,id))%mod;
	}
	long long getmax(long long x,long long l,long long r)
	{
		if(a[x].l>r||a[x].r<l)
		{
			return 0;
		}
		if(a[x].l>=l&&a[x].r<=r)
		{
			return a[x].max1;
		}
		return max(getmax(a[x].lson,l,r),getmax(a[x].rson,l,r));
	}
	long long getmin(long long x,long long l,long long r)
	{
		if(a[x].l>r||a[x].r<l)
		{
			return 1e9;
		}
		if(a[x].l>=l&&a[x].r<=r)
		{
			return a[x].min1;
		}
		return min(getmin(a[x].lson,l,r),getmin(a[x].rson,l,r));
	}
}t;
long long pf(long long x)
{
    return x*(x+1)%mod*(x*2+1)%mod;
}
long long lf(long long x)
{
    long long tmp=x*(x+1)%mod;
    return tmp*tmp%mod;
}
int main()
{
    srand(time(0));
    int n,m;
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
    {
        scanf("%lld",&b[i]);
    }
    t.init(1,n);
    while(m--)
    {
        long long op,l,r;
        scanf("%lld%lld%lld",&op,&l,&r);
        if(op==1)
        {
            t.update(1,l,r);
        }
        else
        {
            long long L=t.getmin(1,l,r),R=t.getmax(1,l,r);
            if(R-L+1!=r-l+1)
            {
                printf("yuanxing\n");
                continue;
            }
            if(t.getsum(1,l,r,1)*4%mod==((lf(R)-lf(L-1))%mod+mod)%mod)
            {
                if(rand()%3==0)
                {
                    if(t.getsum(1,l,r,0)*6%mod==((pf(R)-pf(L-1))%mod+mod)%mod)
                    {
                        printf("damushen\n");
                    }
                    else
                    {
                        printf("yuanxing\n");
                    }
                }
                else
                {
                    printf("damushen\n");
                }
            }
            else
            {
                printf("yuanxing\n");
            }
        }
    }
    return 0;
}
